mapper.select:
SELECT * FROM (
    SELECT T.*, ROWNUM RN FROM (
        SELECT id, order_no, customer_name, total_amount, status, created_at, updated_at
        FROM orders

            is_deleted = 0

                AND (order_no LIKE '%' || #{keyword} || '%' OR customer_name LIKE '%' || #{keyword} || '%')

            AND status = #{status}

        ORDER BY created_at DESC
    ) T WHERE ROWNUM <= #{offset} + #{size}
) WHERE RN > #{offset}

mapper.update:
UPDATE orders
customer_name = #{customerName}, total_amount = #{totalAmount}, remark = #{remark}, updated_at = SYSTIMESTAMP, updated_by = #{updatedBy}
WHERE id = #{id} AND updated_at = #{updatedAt}

UPDATE orders
SET is_deleted = 1, updated_at = SYSTIMESTAMP, updated_by = #{updatedBy}
WHERE id = #{id} AND updated_at = #{updatedAt}

UPDATE orders
SET status = #{status}, updated_at = SYSTIMESTAMP, updated_by = #{updatedBy}
WHERE id = #{id} AND updated_at = #{updatedAt}

UPDATE order_items
SET is_deleted = 1
WHERE order_id = #{orderId}
